function GenericLogo() {
  return (
    <svg viewBox="0 0 48 48" fill="none" stroke="#8b95a5" strokeWidth="2" aria-hidden>
      <path d="M14 34a7 7 0 010-14 8 8 0 0115.5-2A6 6 0 0132 34H14z" strokeLinejoin="round" />
    </svg>
  );
}

export function ConnectorLogo({ type }: { type: string }) {
  switch (type) {
    case "s3":
      return <S3Logo />;
    case "gcs":
      return <GcsLogo />;
    case "azure_blob":
      return <AzureLogo />;
    case "gdrive":
      return <GDriveLogo />;
    default:
      return <GenericLogo />;
  }
}
